impl DefaultClient {
    /// Streaming variant of `chat_stream`. Drives the Rust core stream
    /// natively, yielding each chunk to the caller's block. When called
    /// without a block, returns a `ChatStreamIterator` (Enumerable via its `each`).
    fn chat_stream(&self, req: ChatCompletionRequest) -> Result<magnus::Value, Error> {
        use magnus::IntoValue;
        use magnus::value::ReprValue;
        let inner = self.inner.clone();
        let core_req: liter_llm::ChatCompletionRequest = req.into();
        let runtime = std::sync::Arc::new(tokio::runtime::Runtime::new().map_err(|e| {
            magnus::Error::new(
                unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                e.to_string(),
            )
        })?);
        let stream = runtime
            .block_on(async { inner.chat_stream(core_req).await })
            .map_err(|e| {
                magnus::Error::new(
                    unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                    e.to_string(),
                )
            })?;
        let iterator = ChatStreamIterator {
            inner: Arc::new(tokio::sync::Mutex::new(Some(stream))),
            runtime,
        };
        let ruby = unsafe { Ruby::get_unchecked() };
        if ruby.block_given() {
            // Drive the stream synchronously, yielding each chunk to the block.
            iterator.each()?;
            Ok(ruby.qnil().as_value())
        } else {
            Ok(iterator.into_value_with(&ruby))
        }
    }
}

