fn create_client(args: &[magnus::Value]) -> Result<DefaultClient, Error> {
    let args = magnus::scan_args::scan_args::<
        (String,),
        (Option<magnus::Value>, Option<u64>, Option<u32>, Option<magnus::Value>),
        (),
        (),
        (),
        (),
    >(args)?;
    let (api_key,) = args.required;

    let (base_url, timeout_secs, max_retries, model_hint) = args.optional;

    let base_url: Option<String> = base_url.and_then(|v| {
        if v.is_nil() {
            None
        } else {
            Some(String::try_convert(v).unwrap_or_default())
        }
    });

    let model_hint: Option<String> = model_hint.and_then(|v| {
        if v.is_nil() {
            None
        } else {
            Some(String::try_convert(v).unwrap_or_default())
        }
    });

    let result = liter_llm::create_client(api_key, base_url, timeout_secs, max_retries, model_hint).map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    Ok(DefaultClient {
        inner: Arc::new(result),
    })
}

fn create_client_from_json(json: String) -> Result<DefaultClient, Error> {
    let result = liter_llm::create_client_from_json(&json).map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    Ok(DefaultClient {
        inner: Arc::new(result),
    })
}

fn encode_data_url(args: &[magnus::Value]) -> Result<String, Error> {
    let args = magnus::scan_args::scan_args::<(Vec<u8>,), (Option<magnus::Value>,), (), (), (), ()>(args)?;
    let (bytes,) = args.required;

    let (mime,) = args.optional;

    let mime: Option<String> = mime.and_then(|v| {
        if v.is_nil() {
            None
        } else {
            Some(String::try_convert(v).unwrap_or_default())
        }
    });

    Ok(liter_llm::image::encode_data_url(&bytes, mime.as_deref()))
}

fn decode_data_url(url: String) -> Option<DecodedDataUrl> {
    liter_llm::image::decode_data_url(&url).map(Into::into)
}

fn register_custom_provider(config: magnus::Value) -> Result<(), Error> {
    let config: liter_llm::CustomProviderConfig = {
        let binding_val: CustomProviderConfig = CustomProviderConfig::try_convert(config)
            .map_err(|e| magnus::Error::new(unsafe { Ruby::get_unchecked() }.exception_type_error(), e.to_string()))?;
        binding_val.into()
    };
    let result = liter_llm::provider::custom::register_custom_provider(config.into()).map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    Ok(result)
}

