fn count_request_tokens(args: &[magnus::Value]) -> Result<usize, Error> {
    let args = magnus::scan_args::scan_args::<(String,), (Option<magnus::Value>,), (), (), (), ()>(args)?;
    let (model,) = args.required;

    let (req,) = args.optional;

    let req_core: liter_llm::ChatCompletionRequest = match req {
        Some(_v) if !_v.is_nil() => {
            let binding_val: ChatCompletionRequest = ChatCompletionRequest::try_convert(_v).map_err(|e| {
                magnus::Error::new(
                    unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
                    e.to_string(),
                )
            })?;
            binding_val.into()
        }
        _ => Default::default(),
    };
    let result = liter_llm::count_request_tokens(&model, &req_core).map_err(|e| {
        magnus::Error::new(
            unsafe { Ruby::get_unchecked() }.exception_runtime_error(),
            e.to_string(),
        )
    })?;
    Ok(result)
}

